import { useEffect, useRef, useState } from "react";
import { useInView } from "framer-motion";

import { toPriceFormat } from "../../libs/functions";

import { Button } from "@nextui-org/react";

import ButtonAddCart from "../../components/ButtonAddCart";

import { GrCompare } from "react-icons/gr";
import { scrollStyle } from "../../libs/tvs";

const rowsPerView = 10;
const td_class = "p-2";

export default function TablePrices({
  setItemToComparate = () => {},
  tableAriaLabel = "",
  measureFormat = "",
  rows = [],
  cart = {},
  handleAdd = () => {},
}) {
  const ref = useRef(null);
  const isInView = useInView(ref);

  const [totalVisibleRows, setTotalVisibleRows] = useState(rowsPerView);
  const visibleRows = rows.slice(0, totalVisibleRows);

  const showMore = () => {
    const total_ = totalVisibleRows + rowsPerView;
    setTotalVisibleRows(total_);
  };

  useEffect(() => {
    if (isInView) showMore();
  }, [isInView]);

  return (
    <div
      data-slot="table-container"
      className={"w-full overflow-x-auto " + scrollStyle}
    >
      <table
        aria-label={tableAriaLabel || null}
        className="w-full sm:min-w-[750px] text-tert table-dinamic max-sm:border-separate border-spacing-y-3"
      >
        <thead className="border-b-3">
          <tr>
            <th className="p-2 border-e-3">
              <p>Medida</p>
              {measureFormat || null}
            </th>

            <th colSpan={4} className="p-2">
              <p>
                Precio(xU)
                <span className="font-size-secondary">Unidades minimas</span>
              </p>
            </th>
          </tr>
        </thead>

        <tbody>
          {visibleRows?.map((item) => {
            const noStock = item?.noStock || false;
            const inCart = item.id in cart;

            return (
              <tr
                key={item.id}
                className="even:text-custom2-10 dark:even:text-custom1 group hover:font-semibold group-hover:secondary/30"
              >
                <td
                  className="p-2 text-start whitespace-nowrap sm:border-e-3 max-sm:border-3 max-sm:rounded-t-lg data-[incart=false]:group-hover:bg-custom2 data-[nostock=true]:bg-divider data-[incart=true]:!bg-success/30"
                  data-incart={inCart}
                  data-nostock={noStock}
                >
                  <div className="flex gap-2 justify-end items-center w-full sm:flex-row-reverse">
                    <span>{item.label}</span>
                    <Button
                      color="secondary"
                      isIconOnly
                      className="shadow-md"
                      title="Ver referencia de tamaños"
                      onPress={() => setItemToComparate(item)}
                    >
                      <GrCompare size={22} />
                    </Button>
                  </div>
                </td>

                {item?.price_data?.prices_qtts &&
                  Object.entries(item.price_data.prices_qtts).map(
                    ([qtt, price]) => {
                      const inCart_qtt =
                        inCart && cart[item.id].qtt === Number(qtt);
                      return (
                        <td
                          key={`precio_x${qtt}`}
                          className="p-2 max-sm:last:border-b-3 max-sm:border-x-3 max-sm:last:rounded-b-lg data-[nostock=true]:bg-divider"
                          data-nostock={noStock}
                        >
                          <div className="flex gap-2 justify-end items-center w-full">
                            <div className="flex items-end justify-center">
                              {toPriceFormat(price)}
                              <span className="font-size-secondary">
                                ({qtt}u)
                              </span>
                            </div>

                            <ButtonAddCart
                              inCart={inCart_qtt}
                              itemData={item}
                              handleAdd={() => {
                                let qtt_ = 0;
                                if (!inCart_qtt) qtt_ = Number(qtt);
                                item.qtt = qtt_;

                                handleAdd(item);
                              }}
                            />
                          </div>
                        </td>
                      );
                    }
                  )}
              </tr>
            );
          })}

          <tr>
            <td className="pt-4">
              {totalVisibleRows < rows.length && (
                <Button
                  ref={ref}
                  size="lg"
                  className="bg-custom1-2 text-custom2--2 font-bold text-xl hover:scale-105"
                  title="Mostrar mas"
                  onPress={() => showMore()}
                >
                  +Mas
                </Button>
              )}
            </td>
          </tr>
        </tbody>
      </table>
    </div>
  );
}
